// Filtrar citas de mañana con estado "Pendiente" y preparar mensajes

const manana = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Bogota' }));
manana.setDate(manana.getDate() + 1);
const dd = String(manana.getDate()).padStart(2, '0');
const mm = String(manana.getMonth() + 1).padStart(2, '0');
const yyyy = manana.getFullYear();
const fechaManana = `${dd}/${mm}/${yyyy}`;

const diasSemana = ['domingo','lunes','martes','miércoles','jueves','viernes','sábado'];
const meses = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
const fechaNatural = `${diasSemana[manana.getDay()]} ${manana.getDate()} de ${meses[manana.getMonth()]}`;

const resultados = [];

for (const item of $input.all()) {
  const row = item.json;

  const fecha    = (row['Fecha']     || '').toString().trim();
  const hora     = (row['Hora ']     || row['Hora']    || '').toString().trim();
  const nombre   = (row['Nombre ']   || row['Nombre']  || 'cliente').toString().trim();
  const servicio = (row['Servicio']  || '').toString().trim();
  const estado   = (row['Estado ']   || row['Estado']  || '').toString().trim();
  const rawNum   = (row['Número ']   || row['Número']  || '').toString().trim();

  // SOLO citas con estado "Pendiente"
  if (estado !== 'Pendiente') continue;

  // Limpiar número: quitar @s.whatsapp.net y caracteres no numéricos
  const numero = rawNum.replace(/@s\.whatsapp\.net/g, '').replace(/\D/g, '');

  if (!fecha || !numero || !hora) continue;
  if (fecha !== fechaManana) continue;

  const mensaje =
    `Hola ${nombre} 👋\n\n` +
    `Te recordamos que tienes una cita en *Peluquería Meyer* mañana ` +
    `*${fechaNatural}* a las *${hora}*.\n\n` +
    `✂️ Servicio: *${servicio}*\n\n` +
    `Si necesitas cancelar o reagendar, responde este mensaje 😊`;

  resultados.push({
    json: {
      numero,
      nombre,
      mensaje,
      fecha,
      hora,
      servicio
    }
  });
}

return resultados;
